ntSet{}\n179: \t\t}\n180: \n181: \t\tif _, ok := desiredMetaByPortMap[epHash]; !ok {\n182: \t\t\tdesiredMetaByPortMap[epHash] = \u0026endpointMeta{\n183: \t\t\t\taddressType: addressType,\n184: \t\t\t\tports:       endpointPorts,\n185: \t\t\t}\n186: \t\t}\n187: \n188: \t\tnode, err := r.nodeLister.Get(pod.Spec.NodeName)\n189: \t\tif err != nil {\n190: \t\t\t// we are getting the information from the local informer,\n191: \t\t\t// an error different than IsNotFound should not happen\n192: \t\t\tif !errors.IsNotFound(err) {\n193: \t\t\t\treturn err\n194: \t\t\t}\n195: \t\t\t// If the Node specified by the Pod doesn't exist we want to requeue the Service so we\n196: \t\t\t// retry later, but also update the EndpointSlice without the problematic Pod.\n197: \t\t\t// Theoretically, the pod Garbage Collector will remove the Pod, but we want to avoid\n198: \t\t\t// situations where a reference from a Pod to a missing node can leave the EndpointSlice\n199: \t\t\t// stuck forever.\n200: \t\t\t// On the other side, if the service.Spec.PublishNotReadyAddresses is set we just add the\n201: \t\t\t// Pod, since the user is explicitly indicating that the Pod address should be published.\n202: \t\t\tif !service.Spec.PublishNotReadyAddresses {\n203: \t\t\t\tlogger.Info(\"skipping Pod for Service, Node not found\", \"pod\", klog.KObj(pod), \"service\", klog.KObj(service), \"node\", klog.KRef(\"\", pod.Spec.NodeName))\n204: \t\t\t\terrs = append(errs, fmt.Errorf(\"skipping Pod %s for Service %s/%s: Node %s Not Found\", pod.Name, service.Namespace, service.Name, pod.Spec.NodeName))\n205: \t\t\t\tcontinue\n206: \t\t\t}\n207: \t\t}\n208: \t\tendpoint := podToEndpoint(pod, node, service, addressType)\n209: \t\tif len(endpoint.Addresses) \u003e 0 {\n210: \t\t\tdesiredEndpointsByPortMap[epHash].Insert(\u0026endpoint)\n211: \t\t}\n212: \t}\n213: \n214: \tspMetrics := metrics.NewServicePortCache()\n215: \ttotalAdded := 0\n216: \ttotalRemoved := 0\n217: \n218: \t// Determine changes necessary f